// schema.ts — Figma kiwi binary schema (deflate-compressed, base64).
//
// This is the schema chunk of a REAL Figma clipboard payload (format version 46), i.e. the
// self-describing kiwi schema Figma itself embedded when a user copied layers in the Figma
// editor. It was extracted verbatim from the sample pasteboard data published in the MIT-era
// OSS project interlace-app/fig-kiwi-toolbox (src/utils/sampleData.ts). We reuse the chunk
// byte-for-byte as chunk 0 of our own payloads and only encode chunk 1 (the message) against
// it, so schema and data can never drift apart.
//
// The schema describes Figma's wire format (an interface, not creative content). See
// src/vendor/figma-kiwi/README.md for provenance and format notes.

/** .fig archive format version this schema was captured from. */
export const FIG_VERSION = 46;

/** Deflate-raw-compressed kiwi binary schema, base64. */
export const FIG_SCHEMA_DEFLATED_BASE64 =
"";
